/**
 * @fileoverview ColorPicker view - DOM construction, spectrum / hue / alpha
 *               rendering, and visual-update helpers.
 *
 * All functions receive DOM refs and state; none own private state.
 *
 * @module module/ColorPicker/view
 */

import { CLS, HSL_CHANNELS, RGB_CHANNELS, PART } from './constants.js';
import { mk, hsvToRgb, hsvToHsl, rgbToHex, currentHex } from './helpers.js';

// ═══════════════════════════════════════════
//  BUILD helpers - return root element(s)
// ═══════════════════════════════════════════

/**
 * Build the 2-D saturation / value colour board.
 *
 * @param {HTMLElement} panel
 * @returns {{ board: HTMLElement, boardCursor: HTMLElement }}
 */
export function buildBoard(panel) {
    const wrap = mk('div', CLS.BOARD_WRAP);
    PART.BOARD_WRAP.apply(wrap);
    const board = mk('div', CLS.BOARD);
    PART.BOARD.apply(board);
    const boardCursor = mk('div', CLS.BOARD_CURSOR);
    PART.BOARD_CURSOR.apply(boardCursor);
    board.append(boardCursor);
    wrap.append(board);
    panel.append(wrap);
    return { board, boardCursor };
}

/**
 * Build the hue slider row.
 *
 * @param {HTMLElement} panel
 * @returns {{ hueTrack: HTMLElement, hueThumb: HTMLElement }}
 */
export function buildHueSlider(panel) {
    const row = mk('div', CLS.SLIDER_ROW);
    PART.SLIDER_ROW.apply(row);
    const label = mk('span', CLS.SLIDER_LABEL); label.text('H');
    PART.SLIDER_LABEL.apply(label);
    const hueTrack = mk('div', CLS.HUE_TRACK);
    PART.HUE_TRACK.apply(hueTrack);
    const hueThumb = mk('div', CLS.SLIDER_THUMB);
    PART.SLIDER_THUMB.apply(hueThumb);
    hueTrack.append(hueThumb);
    row.append(label)
       .append(hueTrack);
    panel.append(row);
    return { hueTrack, hueThumb };
}

/**
 * Build the alpha slider row.
 *
 * @param {HTMLElement} panel
 * @returns {{ alphaTrack: HTMLElement, alphaGrad: HTMLElement, alphaThumb: HTMLElement }}
 */
export function buildAlphaSlider(panel) {
    const row = mk('div', CLS.SLIDER_ROW);
    PART.SLIDER_ROW.apply(row);
    const label = mk('span', CLS.SLIDER_LABEL); label.text('A');
    PART.SLIDER_LABEL.apply(label);
    const alphaTrack = mk('div', CLS.ALPHA_TRACK);
    PART.ALPHA_TRACK.apply(alphaTrack);
    const alphaGrad  = mk('div', CLS.ALPHA_GRADIENT);
    PART.ALPHA_GRADIENT.apply(alphaGrad);
    const alphaThumb = mk('div', CLS.SLIDER_THUMB);
    PART.SLIDER_THUMB.apply(alphaThumb);
    alphaTrack.append(alphaGrad)
              .append(alphaThumb);
    row.append(label)
       .append(alphaTrack);
    panel.append(row);
    return { alphaTrack, alphaGrad, alphaThumb };
}

/**
 * Build the preview + hex-input info row.
 *
 * @param {HTMLElement} panel
 * @returns {{ previewOld: HTMLElement, previewCur: HTMLElement, hexInput: HTMLInputElement }}
 */
export function buildInfoRow(panel) {
    const row = mk('div', CLS.INFO_ROW);
    PART.INFO_ROW.apply(row);

    // Preview
    const preview = mk('div', CLS.PREVIEW);
    PART.PREVIEW.apply(preview);
    const previewOld = mk('div', CLS.PREVIEW_OLD);
    PART.PREVIEW_HALF.apply(previewOld);
    previewOld.attr('title', 'Previous colour');
    const previewCur = mk('div', CLS.PREVIEW_CUR);
    PART.PREVIEW_HALF.apply(previewCur);
    previewCur.attr('title', 'Current colour');
    preview.append(previewOld)
           .append(previewCur);
    row.append(preview);

    // Hex input
    const hexGroup = mk('div', CLS.HEX_GROUP);
    PART.HEX_GROUP.apply(hexGroup);
    const hexLabel = mk('label', CLS.HEX_LABEL); hexLabel.text('HEX');
    PART.HEX_LABEL.apply(hexLabel);
    const hexInput = mk('input', CLS.HEX_INPUT);
    PART.HEX_INPUT.apply(hexInput);
    hexInput.attr('type', 'text'); hexInput.attr('maxlength', 9);
    hexGroup.append(hexLabel)
            .append(hexInput);
    row.append(hexGroup);

    panel.append(row);
    return { previewOld, previewCur, hexInput };
}

/**
 * Build a single channel slider row and register its refs.
 *
 * @param {HTMLElement} parent   The group wrapper
 * @param {string}      group   'hsl' | 'rgb'
 * @param {{ k: string, l: string, max: number, u: string }} ch
 * @param {object}      chRefs  Shared ref map to mutate
 * @returns {{ track: HTMLElement, thumb: HTMLElement, input: HTMLInputElement }}
 */
export function buildCh(parent, group, ch, chRefs) {
    const row = mk('div', CLS.CH_ROW);
    PART.CH_ROW.apply(row);
    const lbl = mk('span', CLS.CH_LABEL); lbl.text(ch.l);
    PART.CH_LABEL.apply(lbl);
    const track = mk('div', CLS.CH_TRACK); track.data('ch', ch.k);
    PART.CH_TRACK.apply(track);
    const thumb = mk('div', CLS.SLIDER_THUMB);
    track.append(thumb);
    const input = mk('input', CLS.CH_INPUT);
    PART.CH_INPUT.apply(input);
    input.attr('type', 'number'); input.attr('min', 0); input.attr('max', ch.max);
    row.append(lbl)
       .append(track);
    row.append(input);
    if (ch.u) { const u = mk('span', CLS.CH_UNIT); PART.CH_UNIT.apply(u); u.text(ch.u); row.append(u); }
    parent.append(row);

    const ref = `${group}-${ch.k}`;
    chRefs[ref] = { track, thumb, input };
    return { track, thumb, input };
}

/**
 * Build the HSL / RGB channel tab section.
 *
 * @param {HTMLElement} panel
 * @param {string}      inputMode  Current active tab ('hsl' | 'rgb')
 * @param {object}      chRefs     Shared ref map to mutate
 * @returns {{ tabs: HTMLElement, hslWrap: HTMLElement, rgbWrap: HTMLElement }}
 */
export function buildChannels(panel, inputMode, chRefs) {
    const wrap = mk('div', CLS.CHANNELS_WRAP);
    PART.CHANNELS_WRAP.apply(wrap);

    // Tabs
    const tabs = mk('div', CLS.TABS);
    PART.TABS.apply(tabs);
    ['HSL', 'RGB'].forEach(label => {
        const btn = mk('button', CLS.TAB);
        PART.TAB.apply(btn);
        btn.text(label);
        btn.data('mode', label.toLowerCase());
        if (inputMode === label.toLowerCase()) btn.addClass(CLS.TAB_ACTIVE);
        tabs.append(btn);
    });
    wrap.append(tabs);

    // HSL group
    const hslWrap = mk('div', CLS.CH_GROUP);
    PART.CH_GROUP.apply(hslWrap);
    HSL_CHANNELS.forEach(ch => buildCh(hslWrap, 'hsl', ch, chRefs));
    wrap.append(hslWrap);

    // RGB group
    const rgbWrap = mk('div', CLS.CH_GROUP);
    PART.CH_GROUP.apply(rgbWrap);
    rgbWrap.css('display', 'none');
    RGB_CHANNELS.forEach(ch => buildCh(rgbWrap, 'rgb', ch, chRefs));
    wrap.append(rgbWrap);

    panel.append(wrap);
    return { tabs, hslWrap, rgbWrap };
}

/**
 * Build the swatches palette section.
 *
 * @param {HTMLElement} panel
 * @param {Array<string[]>} swatches  2-D array of hex colours
 * @returns {{ swatchGrid: HTMLElement }}
 */
export function buildSwatches(panel, swatches) {
    const sec = mk('div', CLS.SECTION);
    PART.SECTION.apply(sec);
    const title = mk('div', CLS.SECTION_TITLE); title.text('Swatches');
    PART.SECTION_TITLE.apply(title);
    sec.append(title);
    const grid = mk('div', CLS.SWATCH_GRID);
    PART.SWATCH_GRID.apply(grid);
    swatches.forEach(row => {
        row.forEach(hex => {
            const chip = mk('button', CLS.CHIP);
            PART.CHIP.apply(chip);
            chip.css('background', hex);
            chip.attr('title', hex);
            grid.append(chip);
        });
    });
    sec.append(grid);
    panel.append(sec);
    return { swatchGrid: grid };
}

/**
 * Build the history panel with clear button.
 *
 * @param {HTMLElement} panel
 * @returns {{ historyGrid: HTMLElement, clearBtn: HTMLElement }}
 */
export function buildHistoryPanel(panel) {
    const sec = mk('div', CLS.SECTION);
    PART.SECTION.apply(sec);
    const header = mk('div', CLS.SECTION_HEADER);
    PART.SECTION_HEADER.apply(header);
    const title = mk('span', CLS.SECTION_TITLE); title.text('History');
    PART.SECTION_TITLE.apply(title);
    const clearBtn = mk('button', CLS.CLEAR_BTN); clearBtn.text('Clear');
    PART.CLEAR_BTN.apply(clearBtn);
    header.append(title)
          .append(clearBtn);
    sec.append(header);
    const historyGrid = mk('div', CLS.HISTORY_GRID);
    sec.append(historyGrid);
    panel.append(sec);
    return { historyGrid, clearBtn };
}

/**
 * Render history chips into the history grid.
 *
 * @param {HTMLElement} grid
 * @param {string[]}   history
 */
export function renderHistory(grid, history) {
    if (!grid) return;
    grid.html('');
    if (!history.length) {
        const empty = mk('span', CLS.HISTORY_EMPTY);
        PART.HISTORY_EMPTY.apply(empty);
        empty.text('No colours yet');
        grid.append(empty);
        return;
    }
    history.forEach(hex => {
        const chip = mk('button', CLS.CHIP);
        PART.CHIP.apply(chip);
        chip.css('background', hex);
        chip.attr('title', hex);
        grid.append(chip);
    });
}

/**
 * Build the lite-mode footer (transparent button + hex input).
 *
 * @param {HTMLElement} panel
 * @returns {{ transBtn: HTMLElement, hexInput: HTMLInputElement }}
 */
export function buildLiteFooter(panel) {
    const row = mk('div', CLS.LITE_FOOTER);
    PART.LITE_FOOTER.apply(row);
    const transBtn = mk('button', CLS.LITE_TRANSPARENT);
    PART.LITE_TRANSPARENT.apply(transBtn);
    transBtn.attr('title', 'Set transparent');
    transBtn.html('<span class="' + CLS.LITE_CHECKER + '"></span>');
    PART.LITE_CHECKER.apply(transBtn.find('.' + CLS.LITE_CHECKER));
    row.append(transBtn);

    const hexWrap = mk('div', CLS.LITE_HEX);
    PART.LITE_HEX.apply(hexWrap);
    const hexInput = mk('input', CLS.HEX_INPUT);
    hexInput.attr('type', 'text'); hexInput.attr('maxlength', 7);
    hexWrap.append(hexInput);
    row.append(hexWrap);
    panel.append(row);
    return { transBtn, hexInput };
}

// ═══════════════════════════════════════════
//  UPDATE helpers - mutate DOM based on state
// ═══════════════════════════════════════════

/**
 * Update the colour board's background and cursor position.
 */
export function updateBoard(board, boardCursor, hsv) {
    if (!board) return;
    board.css('background-color', `hsl(${hsv.h}, 100%, 50%)`);
    const x = hsv.s / 100, y = 1 - hsv.v / 100;
    boardCursor.css('left', (x * 100) + '%')
               .css('top', (y * 100) + '%');
}

/**
 * Update the hue thumb position.
 */
export function updateHue(hueThumb, hsv) {
    if (!hueThumb) return;
    hueThumb.css('left', (hsv.h / 360 * 100) + '%');
}

/**
 * Update the alpha gradient and thumb position.
 */
export function updateAlpha(alphaGrad, alphaThumb, hsv, alpha) {
    if (!alphaThumb) return;
    const rgb = hsvToRgb(hsv.h, hsv.s, hsv.v);
    const hex = rgbToHex(rgb.r, rgb.g, rgb.b);
    alphaGrad.css('background', `linear-gradient(to right, transparent, ${hex})`);
    alphaThumb.css('left', (alpha * 100) + '%');
}

/**
 * Update the preview swatches (current + old colour).
 */
export function updatePreview(previewCur, previewOld, hsv, alpha, showAlpha, oldColor) {
    if (!previewCur) return;
    const rgb = hsvToRgb(hsv.h, hsv.s, hsv.v);
    previewCur.css('background', showAlpha
        ? `rgba(${rgb.r},${rgb.g},${rgb.b},${alpha})`
        : rgbToHex(rgb.r, rgb.g, rgb.b));
    if (oldColor) previewOld.css('background', oldColor);
}

/**
 * Update the hex input value.
 */
export function updateHex(hexInput, hsv) {
    if (!hexInput) return;
    hexInput.val(currentHex(hsv).toUpperCase());
}

/**
 * Update a single channel slider thumb + input.
 */
export function updCh(chRefs, ref, val, max) {
    const r = chRefs[ref]; if (!r) return;
    r.input.val(val);
    r.thumb.css('left', (val / max * 100) + '%');
}

/**
 * Set a channel track gradient.
 */
export function setTrackGrad(chRefs, ref, grad) {
    const r = chRefs[ref]; if (!r) return;
    r.track.css('background', grad);
}

/**
 * Update all channel sliders - HSL and RGB.
 */
export function updateChannels(chRefs, hsv) {
    const hsl = hsvToHsl(hsv.h, hsv.s, hsv.v);
    const rgb = hsvToRgb(hsv.h, hsv.s, hsv.v);

    // Thumb positions + input values
    updCh(chRefs, 'hsl-h', hsl.h, 360);
    updCh(chRefs, 'hsl-s', hsl.s, 100);
    updCh(chRefs, 'hsl-l', hsl.l, 100);
    updCh(chRefs, 'rgb-r', rgb.r, 255);
    updCh(chRefs, 'rgb-g', rgb.g, 255);
    updCh(chRefs, 'rgb-b', rgb.b, 255);

    // Track gradients
    setTrackGrad(chRefs, 'hsl-h',
        `linear-gradient(to right, hsl(0,100%,50%),hsl(60,100%,50%),hsl(120,100%,50%),hsl(180,100%,50%),hsl(240,100%,50%),hsl(300,100%,50%),hsl(360,100%,50%))`);
    setTrackGrad(chRefs, 'hsl-s',
        `linear-gradient(to right, hsl(${hsl.h},0%,${hsl.l}%), hsl(${hsl.h},100%,${hsl.l}%))`);
    setTrackGrad(chRefs, 'hsl-l',
        `linear-gradient(to right, hsl(${hsl.h},${hsl.s}%,0%), hsl(${hsl.h},${hsl.s}%,50%), hsl(${hsl.h},${hsl.s}%,100%))`);
    setTrackGrad(chRefs, 'rgb-r',
        `linear-gradient(to right, rgb(0,${rgb.g},${rgb.b}), rgb(255,${rgb.g},${rgb.b}))`);
    setTrackGrad(chRefs, 'rgb-g',
        `linear-gradient(to right, rgb(${rgb.r},0,${rgb.b}), rgb(${rgb.r},255,${rgb.b}))`);
    setTrackGrad(chRefs, 'rgb-b',
        `linear-gradient(to right, rgb(${rgb.r},${rgb.g},0), rgb(${rgb.r},${rgb.g},255))`);
}

/**
 * Update the popup trigger swatch + label.
 */
export function updateTrigger(trigger, hsv) {
    if (!trigger) return;
    const hex = currentHex(hsv).toUpperCase();
    const $swatch = trigger.find('.' + CLS.TRIGGER_SWATCH);
    const $label  = trigger.find('.' + CLS.TRIGGER_HEX);
    if ($swatch.length) $swatch.css('background', hex);
    if ($label.length)  $label.text(hex);
}
