/**
 * @fileoverview ColorPicker state - reactive state helpers.
 *
 * Encapsulates reading / writing localStorage history and
 * provides a factory for the internal HSV + alpha state object.
 *
 * @module module/ColorPicker/state
 */

// ── History persistence ─────────────────────────

/**
 * Load colour history from localStorage.
 *
 * @param {string}  key     localStorage key
 * @param {boolean} persist Whether persistence is enabled
 * @returns {string[]}      Array of hex strings
 */
export function loadHistory(key, persist) {
    if (!persist) return [];
    try {
        const s = localStorage.getItem(key);
        if (s) return JSON.parse(s);
    } catch (_) {}
    return [];
}

/**
 * Save colour history to localStorage.
 *
 * @param {string}   key     localStorage key
 * @param {string[]} history Array of hex strings
 * @param {boolean}  persist Whether persistence is enabled
 */
export function saveHistory(key, history, persist) {
    if (!persist) return;
    try { localStorage.setItem(key, JSON.stringify(history)); } catch (_) {}
}

/**
 * Push a hex colour to the front of the history array, deduplicating.
 *
 * @param {string[]} history   Mutable history array
 * @param {string}   hex       Hex colour (upper-case)
 * @param {number}   maxItems  Maximum history length
 * @returns {string[]}         Same array reference, mutated
 */
export function pushHistory(history, hex, maxItems) {
    const upper = hex.toUpperCase();
    const idx = history.indexOf(upper);
    if (idx !== -1) history.splice(idx, 1);
    history.unshift(upper);
    if (history.length > maxItems) history.length = maxItems;
    return history;
}
